solutions.python:
import sys

class Solution:
    def solve(self, s: str) -> str:
        # count frequencies
        freq = {}
        for ch in s:
            freq[ch] = freq.get(ch, 0) + 1
        # sort characters by (-freq, ch)
        sorted_chars = sorted(freq.items(), key=lambda x: (-x[1], x[0]))
        # build result
        res = []
        for ch, cnt in sorted_chars:
            res.append(ch * cnt)
        return ''.join(res)

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        _ = next(it)  # length, not needed
        s = next(it)
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(s)
    print(ans)

