#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string solve(string s) {
        unordered_map<char, int> freq;
        for (char c : s) freq[c]++;
        vector<pair<char,int>> vec;
        vec.reserve(freq.size());
        for (auto &p : freq) vec.emplace_back(p.first, p.second);
        sort(vec.begin(), vec.end(), [](const pair<char,int>& a, const pair<char,int>& b){
            if (a.second != b.second) return a.second > b.second; // decreasing freq
            return a.first < b.first; // increasing char
        });
        string res;
        for (auto &p : vec) res.append(p.second, p.first);
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s;
    if (!(cin >> s)) return 0;
    Solution sol;
    string ans = sol.solve(s);
    cout << ans << "\n";
    return 0;
}
